import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"消费电子行业审核前文件请求清单（ELE-AUD-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/electronics/audit-checklist.md","filePath":"zh/industry/electronics/audit-checklist.md"}'),h={name:"zh/industry/electronics/audit-checklist.md"};function o(l,t,i,n,s,b){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="消费电子行业审核前文件请求清单-ele-aud-001" tabindex="-1">消费电子行业审核前文件请求清单（ELE-AUD-001） <a class="header-anchor" href="#消费电子行业审核前文件请求清单-ele-aud-001" aria-label="Permalink to &quot;消费电子行业审核前文件请求清单（ELE-AUD-001）&quot;">​</a></h1><blockquote><p><strong>发送时机：</strong> 现场审核前 <strong>4周</strong> 发送给工厂/供应商</p><p><strong>适用范围：</strong> 消费电子OEM/ODM/EMS制造商、PCB/组件供应商</p></blockquote><hr><h2 id="模块一-合法经营资质" tabindex="-1">模块一　合法经营资质 <a class="header-anchor" href="#模块一-合法经营资质" aria-label="Permalink to &quot;模块一　合法经营资质&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>1.1</td><td>营业执照</td><td>有效期内，与实际生产地址一致</td><td>□</td></tr><tr><td>1.2</td><td>环保排污许可证</td><td>有电镀/化学处理工序者必须</td><td>□</td></tr><tr><td>1.3</td><td>安全生产许可证</td><td>如适用</td><td>□</td></tr></tbody></table><hr><h2 id="模块二-劳工与人事" tabindex="-1">模块二　劳工与人事 <a class="header-anchor" href="#模块二-劳工与人事" aria-label="Permalink to &quot;模块二　劳工与人事&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>2.1</td><td>全体员工名单（含派遣工）</td><td>含合同类型、入职日期</td><td>□</td></tr><tr><td>2.2</td><td>最近12个月工资记录</td><td>按月，含实发工资与扣除明细</td><td>□</td></tr><tr><td>2.3</td><td>最近12个月出勤记录</td><td>原始电子打卡数据</td><td>□</td></tr><tr><td>2.4</td><td>劳务派遣合同样本及派遣公司资质</td><td>含人力资源服务许可证</td><td>□</td></tr><tr><td>2.5</td><td>旺季（Q3-Q4）工时统计</td><td>对比淡季，识别系统性超时</td><td>□</td></tr></tbody></table><hr><h2 id="模块三-冲突矿产" tabindex="-1">模块三　冲突矿产 <a class="header-anchor" href="#模块三-冲突矿产" aria-label="Permalink to &quot;模块三　冲突矿产&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>3.1</td><td>冲突矿产申报表（CMRT）最新版</td><td>填写完整，含冶炼厂名单</td><td>□</td></tr><tr><td>3.2</td><td>钴矿产申报表（EMRT）如适用</td><td>含电池材料供应商</td><td>□</td></tr><tr><td>3.3</td><td>RMI认证冶炼厂核验记录</td><td>验证CMRT中冶炼厂认证状态</td><td>□</td></tr><tr><td>3.4</td><td>一级物料供应商的CMRT汇总</td><td>核验供应商填报情况</td><td>□</td></tr></tbody></table><hr><h2 id="模块四-信息安全与知识产权" tabindex="-1">模块四　信息安全与知识产权 <a class="header-anchor" href="#模块四-信息安全与知识产权" aria-label="Permalink to &quot;模块四　信息安全与知识产权&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>4.1</td><td>ISO 27001认证书（如有）</td><td>有效期内</td><td>□</td></tr><tr><td>4.2</td><td>信息安全政策/手册</td><td>当前版本</td><td>□</td></tr><tr><td>4.3</td><td>员工NDA签署记录（汇总）</td><td>确认覆盖率</td><td>□</td></tr><tr><td>4.4</td><td>数据访问权限管理制度</td><td>最小权限原则文件</td><td>□</td></tr><tr><td>4.5</td><td>过去3年信息安全事件记录</td><td>含零事件说明</td><td>□</td></tr></tbody></table><hr><h2 id="模块五-有害物质-rohs-reach" tabindex="-1">模块五　有害物质（RoHS/REACH） <a class="header-anchor" href="#模块五-有害物质-rohs-reach" aria-label="Permalink to &quot;模块五　有害物质（RoHS/REACH）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>5.1</td><td>RoHS符合性声明（DoC）</td><td>针对主要产品类别</td><td>□</td></tr><tr><td>5.2</td><td>SVHC物质披露清单</td><td>REACH附件XVII/XIV相关</td><td>□</td></tr><tr><td>5.3</td><td>第三方有害物质检测报告</td><td>近12个月，由资质实验室出具</td><td>□</td></tr><tr><td>5.4</td><td>危险废物处置记录</td><td>含处置单位许可证</td><td>□</td></tr></tbody></table><hr><h2 id="模块六-管理体系与历史审核" tabindex="-1">模块六　管理体系与历史审核 <a class="header-anchor" href="#模块六-管理体系与历史审核" aria-label="Permalink to &quot;模块六　管理体系与历史审核&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>6.1</td><td>RBA/EICC最新自评报告（SAPR）</td><td>如已完成</td><td>□</td></tr><tr><td>6.2</td><td>最近一次客户或第三方审核报告</td><td>12个月内</td><td>□</td></tr><tr><td>6.3</td><td>CAP整改计划进展</td><td>未关闭项说明</td><td>□</td></tr><tr><td>6.4</td><td>渗透测试/安全评估报告</td><td>如有，近24个月内</td><td>□</td></tr></tbody></table>',20)])])}const _=d(h,[["render",o]]);export{u as __pageData,_ as default};
